class Solution {
public:
    string lastSubstring(string s) {
        int n = s.size();
        for (int i = n - 1; i >= 0; i--) {
            for (int j = i + 1; j < n; j++) {
                string sub = s.substr(i, j - i + 1);
                if (sub > s.substr(i + 1)) {
                    return sub;
                }
            }
        }
        return s;
    }
};
